func (h *Handler) handleError(w http.ResponseWriter, r *http.Request, err error) {
    if appErr, ok := apperror.AsAppError(err); ok {
        h.respondJSON(w, appErr.Status, appErr)
        return
    }
    switch {
    case errors.Is(err, apperror.ErrNotFound):
        h.respondJSON(w, http.StatusNotFound, map[string]string{"error": "not found"})
    case errors.Is(err, apperror.ErrUnauthorized):
        h.respondJSON(w, http.StatusUnauthorized, map[string]string{"error": "unauthorized"})
    default:
        h.logger.Error("unexpected error", "error", err, "path", r.URL.Path)
        h.respondJSON(w, http.StatusInternalServerError, map[string]string{"error": "internal error"})
    }
}

func Recovery(logger *slog.Logger) func(http.Handler) http.Handler {
    return func(next http.Handler) http.Handler {
        return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
            defer func() {
                if rec := recover(); rec != nil {
                    logger.Error("panic recovered",
                        "panic", rec,
                        "stack", string(debug.Stack()),
                        "path", r.URL.Path,
                    )
                    http.Error(w, "Internal Server Error", http.StatusInternalServerError)
                }
            }()
            next.ServeHTTP(w, r)
        })
    }
}

// Go 1.20+: errors.Join
func ValidateUser(input CreateUserInput) error {
    var errs []error
    if input.Email == "" { errs = append(errs, errors.New("email required")) }
    if input.Name == ""  { errs = append(errs, errors.New("name required")) }
    return errors.Join(errs...)
}
